import React, { useState } from 'react';

function App() {
  const [cpf, setCpf] = useState('');
  const [password, setPassword] = useState('');
  const [loggedIn, setLoggedIn] = useState(false);
  const [error, setError] = useState('');

  // hard–coded credentials for now; will replace with API call later
  const validCpf = '00000000000';
  const validPassword = 'secret';

  const handleSubmit = (e) => {
    e.preventDefault();
    if (cpf === validCpf && password === validPassword) {
      setLoggedIn(true);
      setError('');
    } else {
      setError('CPF ou senha inválidos.');
    }
  };

  if (!loggedIn) {
    return (
      <div className="login-container">
        <h2>Login</h2>
        <form onSubmit={handleSubmit}>
          <div>
            <label>CPF:</label>
            <input
              type="text"
              value={cpf}
              onChange={(e) => setCpf(e.target.value)}
            />
          </div>
          <div>
            <label>Senha:</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          <button type="submit">Entrar</button>
        </form>
        {error && <p style={{ color: 'red' }}>{error}</p>}
      </div>
    );
  }

  return (
    <div className="App">
      <header className="App-header">
        <h1>Cartório de Registros de Títulos e Documentos de Pessoas Civis</h1>
        <p>Aplicação inicial em React.</p>
      </header>
    </div>
  );
}

export default App;
